1636	  if (abs >= 1e9) return sign + "$" + (abs / 1e9).toFixed(2) + "B";
1637	  if (abs >= 1e6) return sign + "$" + (abs / 1e6).toFixed(2) + "M";
1638	  if (abs >= 1e3) return sign + "$" + (abs / 1e3).toFixed(2) + "K";
1639	  return sign + "$" + abs.toFixed(2);
