/* style.css — SIGNAL Trading Terminal Styles */

/* =========================================================================
   Design Tokens
   ========================================================================= */

:root {
  /* Backgrounds */
  --bg-primary: #0d1117;
  --bg-surface: #161b22;
  --bg-surface-2: #1c2128;
  --bg-surface-3: #21262d;
  --bg-hover: rgba(177, 186, 196, 0.06);
  --bg-active: rgba(177, 186, 196, 0.1);

  /* Borders */
  --border: #30363d;
  --border-muted: #21262d;
  --border-emphasis: #484f58;

  /* Text */
  --text-primary: #e6edf3;
  --text-secondary: #8b949e;
  --text-muted: #6e7681;
  --text-faint: #484f58;

  /* Semantic */
  --green: #3fb950;
  --green-bg: rgba(63, 185, 80, 0.1);
  --green-border: rgba(63, 185, 80, 0.3);
  --red: #f85149;
  --red-bg: rgba(248, 81, 73, 0.1);
  --red-border: rgba(248, 81, 73, 0.3);
  --yellow: #d29922;
  --yellow-bg: rgba(210, 153, 34, 0.1);
  --yellow-border: rgba(210, 153, 34, 0.3);
  --blue: #58a6ff;
  --blue-bg: rgba(88, 166, 255, 0.1);
  --blue-border: rgba(88, 166, 255, 0.3);

  /* Spacing (4px grid) */
  --sp-1: 4px;
  --sp-2: 8px;
  --sp-3: 12px;
  --sp-4: 16px;
  --sp-5: 20px;
  --sp-6: 24px;
  --sp-8: 32px;

  /* Radius */
  --radius-sm: 4px;
  --radius-md: 6px;
  --radius-lg: 8px;
  --radius-full: 9999px;

  /* Transitions */
  --ease-out: cubic-bezier(0.16, 1, 0.3, 1);
  --duration-fast: 120ms;
  --duration: 180ms;
  --duration-slow: 300ms;

  /* Sidebar */
  --sidebar-width: 260px;

  /* Header / Status bar */
  --header-height: 44px;
  --statusbar-height: 28px;
}

/* =========================================================================
   Dashboard Grid
   ========================================================================= */

.dashboard {
  display: grid;
  grid-template-columns: var(--sidebar-width) 1fr;
  grid-template-rows: var(--header-height) 1fr var(--statusbar-height);
  height: 100dvh;
  width: 100%;
}

/* =========================================================================
   Header
   ========================================================================= */

.header {
  grid-column: 1 / -1;
  grid-row: 1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 var(--sp-4);
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  z-index: 20;
  gap: var(--sp-4);
}

.header-left {
  display: flex;
  align-items: center;
  gap: var(--sp-4);
}

.logo {
  font-family: 'JetBrains Mono', monospace;
  font-weight: 700;
  font-size: 16px;
  letter-spacing: 0.08em;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: var(--sp-2);
}

.logo-icon {
  width: 20px;
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.logo-icon svg {
  width: 20px;
  height: 20px;
}

.header-divider {
  width: 1px;
  height: 20px;
  background: var(--border);
}

.clock {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  color: var(--text-secondary);
  font-variant-numeric: tabular-nums lining-nums;
  letter-spacing: 0.02em;
}

.header-right {
  display: flex;
  align-items: center;
  gap: var(--sp-3);
}

.header-stat {
  display: flex;
  align-items: center;
  gap: var(--sp-1);
  font-size: 11px;
  color: var(--text-secondary);
}

.header-stat .value {
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums lining-nums;
  color: var(--text-primary);
  font-weight: 500;
}

/* Connection status */
.connection-status {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11px;
  color: var(--text-secondary);
}

.status-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--green);
  position: relative;
}

.status-dot.connected::after {
  content: '';
  position: absolute;
  inset: -3px;
  border-radius: 50%;
  background: var(--green);
  opacity: 0.4;
  animation: pulse 2s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { transform: scale(1); opacity: 0.4; }
  50% { transform: scale(1.8); opacity: 0; }
}

.status-dot.disconnected {
  background: var(--red);
}

.status-dot.disconnected::after {
  display: none;
}

.btn-header {
  display: flex;
  align-items: center;
  gap: var(--sp-1);
  padding: 4px 10px;
  font-size: 11px;
  font-weight: 500;
  color: var(--text-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  background: var(--bg-surface-2);
  transition: all var(--duration) var(--ease-out);
  white-space: nowrap;
}

.btn-header:hover {
  background: var(--bg-surface-3);
  color: var(--text-primary);
  border-color: var(--border-emphasis);
}

.btn-header:active {
  transform: scale(0.97);
}

.btn-header svg {
  width: 14px;
  height: 14px;
  flex-shrink: 0;
}

/* Mobile hamburger */
.hamburger-btn {
  display: none;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  border-radius: var(--radius-md);
  color: var(--text-secondary);
  transition: all var(--duration) var(--ease-out);
}

.hamburger-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.hamburger-btn svg {
  width: 18px;
  height: 18px;
}

/* =========================================================================
   Sidebar
   ========================================================================= */

.sidebar {
  grid-column: 1;
  grid-row: 2 / 4;
  background: var(--bg-surface);
  border-right: 1px solid var(--border);
  overflow-y: auto;
  overscroll-behavior: contain;
  padding: var(--sp-3);
  display: flex;
  flex-direction: column;
  gap: var(--sp-4);
}

.sidebar-section {
  display: flex;
  flex-direction: column;
  gap: var(--sp-2);
}

.sidebar-label {
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-muted);
  padding: 0 var(--sp-1);
}

/* Search input */
.search-wrap {
  position: relative;
}

.search-wrap svg {
  position: absolute;
  left: 8px;
  top: 50%;
